import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface AvailabilityData {
  location: string;
  availability: {
    totalSpots: number;
    availableSpots: number;
  };
  nearestLocation: {
    name: string;
    distance: string;
    hourlyRate: number;
  };
  hourlyRates: {
    hour: string;
    rate: number;
  }[];
}

export default function Widget() {
  const data = response.data as AvailabilityData;
  const clipPathId = 'clip-path-id';

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FAF3E0' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body1" fontWeight={700} sx={{ color: '#6D4C41' }}>
              {data.location}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1.5 }}>
              Available Spots: {data.availability.availableSpots} / {data.availability.totalSpots}
            </Typography>
            <Stack direction="row" spacing={0.5}>
              <Chip label={`Nearest: ${data.nearestLocation.name}`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
              <Chip label={`Distance: ${data.nearestLocation.distance}`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
              <Chip label={`Rate: $${data.nearestLocation.hourlyRate}/hr`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
            </Stack>
          </Box>

          <Divider sx={{ bgcolor: '#BCAAA4' }} />

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: data.hourlyRates.map((rate) => rate.rate),
                  color: '#8D6E63',
                  label: 'Rate',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: data.hourlyRates.map((rate) => rate.hour),
                  id: 'hours',
                },
              ]}
              yAxis={[{ id: 'rate' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis axisId="hours" tickLabelStyle={{ fontSize: 10, fill: '#6D4C41' }} />
              <ChartsYAxis axisId="rate" tickLabelStyle={{ fontSize: 10, fill: '#6D4C41' }} />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
